// RAJ - to test menu issue remove data from parameters and change comments below
//	getMenu: function(menuName, page_id){
	getMenu: function(data, menuName, page_id){		
		switch (menuName) {
			case "Task Menu":
				this.items = this._createTaskMenu(page_id, menuName);
				break;
			case "Organizational Menu":
				this.items = this._createOrganizationalMenu(page_id, menuName);
				break;
			case "Template Menu":
				// STRY0126152 - return the page menu to allow selection to save the preference.
				this.items = this._createTemplateMenu(page_id, menuName);
		}
		// find the current page in the items and set the top menu to the page selected
		var currentPage = this._getMenuItemByPageId(page_id, this.items);
// to test returning menu to the data object instead of updating data, comment the lines form beginning BLOCK 1 to end BLOCK 1, and uncomment beginning BLOCK 2 to end BLOCK 2
// beginning BLOCK 1-----------------------
		data.label = currentPage.label;
		data.type= currentPage.type;
		data.src = currentPage.src;
		data.count = this.items.length;
		data.omitBadge = true;
		data.taskerPageMenu = true;
		data.items = this.items;

// end BLOCK 1-----------------------		
//		return data;
// beginning BLOCK 2-----------------------

//		creating menu in here and not passing data and doing the lines above fails and I am not sure why
/*		var menu = {};
		menu.label = currentPage.label;
		menu.type= currentPage.type;
		menu.src = currentPage.src;
		menu.count = this.items.length;
		menu.omitBadge = true;
		menu.taskerPageMenu = true;
		menu.items = this.items;
		return menu;
*/
// end BLOCK 2-----------------------
	},

	_createTaskMenu: function(page_id, menuName){
		return this._loadPageTaskViewsMenu(page_id, menuName);
	},

	_createOrganizationalMenu: function(page_id, menuName){
		return this._loadPageOrganizationalViewsMenu(page_id, menuName);
	},

	_createTemplateMenu: function(page_id, menuName){
		return this._loadPageTemplateViewsMenu(page_id, menuName);
	},


	_getMenuItemByPageId: function(page_id, page_array){
		for (var i=0; i < page_array.length; i++) {
			var menuItem = page_array[i];
			if (menuItem.id === page_id) {
				menuItem.disabled = true;
				return menuItem;
			}
		}
/*				var item;
		for (item in pageTaskViewsMenu){
			var menuItem = pageTaskViewsMenu[item];
			if(menuItem.id == page_id){
				// disable  the menu item for the current page
				menuItem.disabled = true;
			}
		}
		*/
	},

    type: 'TaskerPageMenus'
};
